messages.content:
你是 marketting-planning-intent 项目的 attribute agent。
只归因当前单轮 intent-recognition 链路：request_normalization、intent_api_call、adapter_extraction、label_mapping；不要把 planning/SSE generation 的问题归入本项目。
优先使用 intent_contract_probe 定位 intent label、required slots/entities、confidence threshold、fallback policy 或 label_mapping 的当前证据差异。
只能输出 AttributeResult JSON 所需字段；证据不足时用 evidence_strength=none/weak 和 root_cause_hypothesis 表达缺口。
最终只输出 AttributeResult JSON 所需字段：expectation_attributions、suspected_locations、root_cause_hypothesis、evidence、evidence_strength。

## 输出约束：attribute 归因分析输出
你的输出必须是合法 JSON，且严格符合以下 JSON Schema：
```json
{
  "type": "object",
  "properties": {
    "expectation_attributions": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/ExpectationAttribution"
      },
      "minItems": 1
    },
    "suspected_locations": {
      "type": "array",
      "items": {}
    },
    "root_cause_hypothesis": {
      "type": "string",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "items": {}
    },
    "evidence_strength": {
      "type": "string",
      "minLength": 1
    }
  },
  "additionalProperties": false,
  "$defs": {
    "ExpectationAttribution": {
      "type": "object",
      "properties": {
        "expectation_id": {
          "type": "string",
          "minLength": 1
        },
        "fulfillment_status": {
          "type": "string",
          "minLength": 1
        },
        "suspected_locations": {
          "type": "array",
          "items": {}
        },
        "root_cause_hypothesis": {
          "type": "string",
          "minLength": 1
        },
        "evidence": {
          "type": "array",
          "items": {}
        }
      },
      "additionalProperties": false,
      "required": [
        "expectation_id",
        "fulfillment_status"
      ]
    }
  },
  "required": [
    "expectation_attributions",
    "root_cause_hypothesis"
  ]
}
```

### 强约束
- 最终回答必须只包含一个 JSON object；不要输出 Markdown，不要使用 ```json 代码块，不要在 JSON 外输出解释、前缀或后缀。
- 最终回答首字符必须是 `{`，末字符必须是 `}`。
- JSON 字符串内部如需引用用户原词，禁止直接写未转义英文双引号；请使用中文引号“”或转义为 `\"`。
- 必须包含 `required` 列表中的所有字段。
- 每个字段值必须匹配 schema 中的类型。
- 以下字段必须非空（空字符串/空数组/空对象/None 均视为不合规，会被阻断）：['expectation_attributions', 'root_cause_hypothesis']
- `additionalProperties: false`：禁止输出 schema 未定义的字段。
- 禁止把 schema 里的类型描述符（如 "string"）原样当作内容填进去——每个字段必须填入真实内容。

{
  "expectation_attributions": [
    {
      "expectation_id": "意图标签为 customer_portrait",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
        {
          "stage": "intent_api_call",
          "component": "意图分类模型/提示词",
          "evidence": "模型输出 'other' 而不是 'customer_portrait'，置信度仅 0.5"
        },
        {
          "stage": "adapter_extraction",
          "component": "响应解析逻辑",
          "evidence": "从原始响应中提取的 intent 为 'other'，未纠正"
        }
      ],
      "root_cause_hypothesis": "意图识别模型或提示词未能将用户查询“帮我看看上季度买了重疾险的客户都是啥样的？”正确分类为客户画像意图，将其误判为其他意图，导致输出标签错误。",
      "evidence": [
        "reference_contract 预期 intent=customer_portrait",
        "adapter_extraction 实际输出 intent=other",
        "runtime_checks 确认 actual_mapping=other, expected_intent=customer_portrait"
      ]
    },
    {
      "expectation_id": "置信度达到业务阈值",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
        {
          "stage": "intent_api_call",
          "component": "置信度计算逻辑",
          "evidence": "输出置信度 0.5，远低于阈值 0.95"
        }
      ],
      "root_cause_hypothesis": "由于意图分类错误，模型给出的置信度较低（0.5），未能满足业务要求的 0.95 阈值。根本原因仍为意图分类错误。",
      "evidence": [
        "reference_contract 预期 confidence >= 0.95",
        "实际 confidence = 0.5"
      ]
    },
    {
      "expectation_id": "提取关键实体 target_value",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
        {
          "stage": "adapter_extraction / intent_api_call",
          "component": "实体抽取逻辑",
          "evidence": "未抽取到 target_value 实体，最终值为 null"
        }
      ],
      "root_cause_hypothesis": "实体抽取可能依赖于意图识别结果，当意图被错误分类为 'other' 时，实体抽取流程未能触发或未能识别“重疾险”为 target_value；或者实体抽取组件本身存在缺陷，未从查询中提取该实体。",
      "evidence": [
        "输入查询明确包含“重疾险”",
        "实际输出 target_value 为 null",
        "intent_contract_probe 未提及该实体（missing_required_slots 为空）"
      ]
    }
  ],
  "suspected_locations": [
    {
      "stage": "intent_api_call",
      "summary": "意图分类模型的 prompt 或配置导致对客户画像意图的识别失败，输出错误的 intent 标签和低置信度。"
    },
    {
      "stage": "adapter_extraction",
      "summary": "从 API 响应中提取意图和实体的逻辑可能无法纠正模型的错误输出，并导致实体缺失。"
    },
    {
      "stage": "label_mapping",
      "summary": "尽管映射表包含 customer_portrait，但上游传入的意图已是 other，映射未改变结果。此外 runtime_checks 指出 raw_intent=None，可能存在原始响应中的意图未被正确解析，导致最终落入 other。"
    }
  ],
  "root_cause_hypothesis": "在 intent_api_call 阶段，意图识别模型（或规则）未能将用户查询正确分类为 customer_portrait，而给出了 other 标签和低置信度（0.5）。随后 adapter_extraction 和 label_mapping 均传递此错误标签，导致最终输出与参考合同不符。同时，由于意图错误或实体抽取逻辑缺陷，未从查询中提取到关键实体“重疾险”。整体失败根源在于意图分类组件的准确率和置信度未达到业务要求。",
  "evidence": [
    {
      "source": "run_trace.execution_trace",
      "data": {
        "stage": "adapter_extraction",
        "evidence": {
          "confidence": 0.5,
          "intent": "other",
          "subIntent": "其他意图"
        }
      }
    },
    {
      "source": "reference_contract",
      "data": {
        "intent": "customer_portrait",
        "confidence": 0.95,
        "target_value": "重疾险"
      }
    },
    {
      "source": "runtime_checks",
      "data": {
        "actual_mapping": "other",
        "expected_intent": "customer_portrait",
        "raw_intent": null,
        "confidence": "high",
        "root_cause": {
          "category": "label_mapping",
          "summary": "运行时 raw_intent=None 经项目映射得到 other，但当前 reference contract 期望 customer_portrait。"
        }
      }
    },
    {
      "source": "intent_contract_probe",
      "data": {
        "intent_match": false,
        "actual_confidence": 0.5,
        "actual_intent": "other"
      }
    }
  ],
  "evidence_strength": "high"
}

